import React, { Component } from 'react';
import PropTypes from 'prop-types';
import './Header.css';

class Header extends Component {
  constructor(props) {
    super(props);
    this.state = { isScrollOn: true };

    this.scrollBtn = this.scrollBtn.bind(this);
  }

  scrollBtn(e) {
    e.preventDefault();
    this.setState({
      isScrollOn: false,
    });
  }

  render() {
    const { children } = this.props;
    const { isScrollOn } = this.state;
    return (
      <header>
        {children}
        <div className={isScrollOn ? 'Scroll-btn' : 'Scroll-btn-inactive'}>
          <button type="button" onClick={this.scrollBtn}>Scroll</button>
          <div className="Scroll-indicator" />
        </div>
      </header>
    );
  }
}

Header.propTypes = {
  children: PropTypes.string.isRequired,
};

export default Header;
