import React, { Component } from 'react';
import PropTypes from 'prop-types';
import { Link } from 'react-router-dom';
import './Nav.css';

import menuOpen from '../../img/icons/menu-open.svg';
import menuClose from '../../img/icons/menu-close.svg';

class Nav extends Component {
  constructor(props) {
    super(props);
    this.state = { isToggleOn: false };

    this.toggleMenu = this.toggleMenu.bind(this);
    this.closeMenu = this.closeMenu.bind(this);
  }

  toggleMenu(e) {
    e.preventDefault();
    this.setState(state => ({
      isToggleOn: !state.isToggleOn,
    }));
  }

  closeMenu() {
    this.setState({
      isToggleOn: false,
    });
  }

  render() {
    const { brand } = this.props;
    const { isToggleOn } = this.state;
    return (
      <nav className="Nav">
        <Link className="Nav-brand" to="/">
          { brand }
        </Link>
        <button className="Menu-button" type="button" onClick={this.toggleMenu}>
          <img src={isToggleOn ? menuClose : menuOpen} alt="Menu Open Button - Dylan Howard Web and App Design and Development" />
        </button>
        <ul className={isToggleOn ? 'Nav-links-active' : 'Nav-links'}>
          <li className="Nav-link">
            <Link to="/" onClick={this.closeMenu}>Work</Link>
          </li>
          <li className="Nav-link">
            <Link to="/about" onClick={this.closeMenu}>About</Link>
          </li>
          <li className="Nav-link">
            <Link to="/contact" onClick={this.closeMenu}>Contact</Link>
          </li>
        </ul>
      </nav>
    );
  }
}
// <ul className={this.state.toggleOn ? 'Nav-links-active' : 'Nav-links'}>

Nav.propTypes = {
  brand: PropTypes.string.isRequired,
};

export default Nav;
