import React from 'react';
import './Project.css';
import Header from '../Header/Header';
import WorkAPI from '../WorkAPI';

const Project = ({ match }) => {
  const work = WorkAPI.get(
    match.params.title,
  );
  return (
    <div>
      <Header>
        <h1>{work.title}</h1>
        <p className="Site-hook">
          {work.description}
        </p>
        <p>
          <a className="Bright-link" href={work.link}>Click here to see the demo</a>
        </p>
      </Header>
      <div className="Project-container" id="Photos">
        <div className="Project">
          <img src={require(`../../../img/prj/${work.image}`)} alt={`Dylan Howard Web Design and Development - ${work.description}`}/>
        </div>
      </div>
    </div>
  );
};


export default Project;
